import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it)); m = int(next(it))
    adj = [[] for _ in range(n+1)]
    radj = [[] for _ in range(n+1)]
    for _ in range(m):
        a = int(next(it)); b = int(next(it))
        adj[a].append(b)
        radj[b].append(a)
    start = 1
    visited = [False]*(n+1)
    stack = [start]
    visited[start] = True
    while stack:
        u = stack.pop()
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                stack.append(v)
    for i in range(1, n+1):
        if not visited[i]:
            print("NO")
            print(start, i)
            return
    visited2 = [False]*(n+1)
    stack = [start]
    visited2[start] = True
    while stack:
        u = stack.pop()
        for v in radj[u]:
            if not visited2[v]:
                visited2[v] = True
                stack.append(v)
    for i in range(1, n+1):
        if not visited2[i]:
            print("NO")
            print(i, start)
            return
    print("YES")

if __name__ == "__main__":
    main()
